+            bag_3_metadata_.starting_time.time_since_epoch().count());
+  EXPECT_EQ(saved_metadata_.back().duration.count(),
+    std::chrono::duration_cast<std::chrono::nanoseconds>(std::chrono::seconds{21}).count());
+}

